code = """import json
import re

# Get the full business data from storage
business_data = locals()['var_functions.query_db:8']

# Debug: Check the first few descriptions to understand the format
print('Sample descriptions:')
for i, biz in enumerate(business_data[:5]):
    desc = biz.get('description', '')
    print(f"{i}: {desc}")

# Try different patterns to extract state
def extract_state_v2(description):
    if not description:
        return None
    
    # Pattern 1: Look for 2-letter state code before comma after city
    # Format: "in City, ST,"
    pattern1 = r'([A-Z]{2}),'
    match1 = re.search(pattern1, description)
    if match1:
        return match1.group(1)
    
    # Pattern 2: Look for state at the end or middle
    pattern2 = r'([A-Z]{2})\b'
    matches = re.findall(pattern2, description)
    
    # Filter out common false positives
    common_words = {'IN', 'AT', 'TO', 'FOR', 'AND', 'THE', 'A', 'ON', 'BY', 'OF', 'IT'}
    valid_states = [m for m in matches if m not in common_words]
    
    if valid_states:
        return valid_states[0]
    
    return None

# Test extraction on first business
test_biz = business_data[0]
test_state = extract_state_v2(test_biz.get('description', ''))
print(f"Test extraction on first business:")
print(f"Description: {test_biz.get('description', '')}")
print(f"Extracted state: {test_state}")

# Process all businesses
businesses = []
for biz in business_data:
    description = biz.get('description', '')
    state = extract_state_v2(description)
    review_count = int(str(biz.get('review_count', 0)))
    business_id = biz.get('business_id')
    
    if state:
        businesses.append({
            'business_id': business_id,
            'state': state,
            'review_count': review_count,
            'description': description
        })

print(f"Total businesses with extracted state: {len(businesses)}")
if businesses:
    print(f"Sample state extractions:")
    for i, biz in enumerate(businesses[:10]):
        print(f"  {biz['state']}: {biz['business_id']} - {biz['review_count']} reviews")

print("__RESULT__:")
print(json.dumps({
    'total_businesses': len(business_data),
    'businesses_with_state': len(businesses),
    'sample_states': [b['state'] for b in businesses[:10]] if businesses else []
}))"""

